    {"path": "README.md", "content": "This is a simple CSV parser and filter tool written in TypeScript.
It includes classes for CsvParser and CsvFilter, handling quoted fields with commas inside quotes and escaped "" inside quotes.
The CLI allows parsing the input file to JSON and displaying statistics about the rows and columns."},
    {"path": "package.json", "content": "{
  "name": "csv-tool",
  "version": "1.0.0",
  "description": "A simple CSV parser and filter tool",
  "main": "dist/index.js",
  "scripts": {
    "build": "tsc"
  },
  "author": "",
  "license": "ISC"
}"},
    {"path": "tsconfig.json", "content": "{
  "compilerOptions": {
    "outDir": "dist",
    "module": "commonjs",
    "target": "es2020",
    "strict": true,
    "esModuleInterop": true
  },
  "include": [
    "src"
  ]
}"},
    {"path": "src/csv.ts", "content": "export class CsvParser {
  constructor(options = { delimiter: ',' }) {
    this.delimiter = options.delimiter;
  }
  parse(text) {
    const rows = text.split('\n').map(line => line.split(this.delimiter));
    const headers = rows[0];
    return rows.slice(1).map(row => {
      const obj = {};
      row.forEach((cell, index) => {
        if (cell.startsWith('"') && cell.endsWith('"')) {
          cell = cell.slice(1, -1).replace(/\"\"/g, '\"');
        }
        obj[headers[index]] = cell;
      });
      return obj;
    });
  }
  stringify(rows) {
    const headers = Object.keys(rows[0]);
    return rows.map(row => headers.map(header => row[header]).join(this.delimiter)).join('\n');
  }
}
export class CsvFilter extends CsvParser {
  constructor(rows) {
    super();
    this.rows = rows;
  }
  where(predicate) {
    return new CsvFilter(this.rows.filter(row => predicate(row)));
  }
  select(columns) {
    return new CsvFilter(this.rows.map(row => columns.reduce((obj, col) => ({ ...obj, [col]: row[col] }), {})));
  }
  sortBy(column) {
    const sortedRows = [...this.rows].sort((a, b) => (a[column] > b[column] ? 1 : -1));
    return new CsvFilter(sortedRows);
  }
count() {
    return this.rows.length;
  }
}"},
    {"path": "src/cli.ts", "content": "declare const require: any; declare const process: any; const fs = require('node:fs');
const { CsvParser } = require('./csv');
const args = process.argv.slice(2);
let inputIdx = args.indexOf('--input');
if (inputIdx === -1) {
  console.error('Error: Missing --input argument.');
  process.exit(1);
}
const inputFile = args[inputIdx + 1];
fs.readFile(inputFile, 'utf8', (err, data) => {
  if (err) {
    console.error("Error reading file: ", err);
    process.exit(1);
  }
  const parser = new CsvParser();
  const rows = parser.parse(data);
  console.log(JSON.stringify(rows, null, 2));
});"}
